best_attempt.sparql:
SELECT ?player ?playerLabel (xsd:float(?rushYards) / xsd:float(?carries) AS ?avgYPC)
WHERE {
  ?player wdt:P31 wd:Q12569;
         wdt:P3225 ?rushYards;
         wdt:P3226 ?carries.
  ?player rdfs:label ?playerLabel.
  FILTER(lang(?playerLabel) = "en").
  FILTER(?carries > 0)
}
ORDER BY DESC(?avgYPC)
LIMIT 1
